import{_ as c,c as t,a1 as h,o as a}from"./chunks/framework.BDxlaA_J.js";const s=JSON.parse('{"title":"Denial of Service","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/0-Introduction.md","filePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/0-Introduction.md"}'),i={name:"vi/categories/ethical-hacking-labs/9-denial-of-service/0-Introduction.md"};function o(g,n,e,r,l,u){return a(),t("div",null,n[0]||(n[0]=[h('<h1 id="denial-of-service" tabindex="-1">Denial of Service <a class="header-anchor" href="#denial-of-service" aria-label="Permalink to &quot;Denial of Service&quot;">​</a></h1><p>Trong điện toán, tấn công từ chối dịch vụ (tấn công DoS) là một cuộc tấn công mạng trong đó thủ phạm tìm cách làm cho máy hoặc tài nguyên mạng không thể sử dụng được đối với người dùng dự định bằng cách tạm thời hoặc vô thời hạn gián đoạn dịch vụ của một máy chủ được kết nối với Internet. Từ chối dịch vụ thường được thực hiện bằng cách tràn ngập máy hoặc tài nguyên mục tiêu bằng các yêu cầu thừa nhằm cố gắng quá tải hệ thống và ngăn chặn một số hoặc tất cả các yêu cầu hợp lệ được xử lý.</p><h3 id="cac-cuoc-tan-cong-dos-thuong-thuoc-2-loai" tabindex="-1">Các cuộc tấn công DoS thường thuộc 2 loại: <a class="header-anchor" href="#cac-cuoc-tan-cong-dos-thuong-thuoc-2-loai" aria-label="Permalink to &quot;Các cuộc tấn công DoS thường thuộc 2 loại:&quot;">​</a></h3><h3 id="tan-cong-tran-bo-đem-buffer-overflow" tabindex="-1">Tấn công tràn bộ đệm (Buffer overflow) <a class="header-anchor" href="#tan-cong-tran-bo-đem-buffer-overflow" aria-label="Permalink to &quot;Tấn công tràn bộ đệm (Buffer overflow)&quot;">​</a></h3><p>Một loại tấn công trong đó tràn bộ đệm bộ nhớ có thể khiến máy tiêu tốn toàn bộ dung lượng ổ cứng, bộ nhớ hoặc thời gian CPU. Dạng khai thác này thường dẫn đến hành vi chậm chạp, lỗi hệ thống hoặc các hành vi bất lợi khác của máy chủ, dẫn đến từ chối dịch vụ.</p><h3 id="tan-cong-tran-ngap-flood-attacks" tabindex="-1">Tấn công tràn ngập (Flood attacks) <a class="header-anchor" href="#tan-cong-tran-ngap-flood-attacks" aria-label="Permalink to &quot;Tấn công tràn ngập (Flood attacks)&quot;">​</a></h3><p>Bằng cách tràn ngập một máy chủ mục tiêu với lượng gói tin vượt quá khả năng xử lý, một tác nhân độc hại có thể quá tải dung lượng máy chủ, dẫn đến từ chối dịch vụ. Để大多数 các cuộc tấn công tràn DoS thành công, tác nhân độc hại phải có nhiều băng thông khả dụng hơn mục tiêu.</p><p>Về mặt lịch sử, các cuộc tấn công DoS thường khai thác các lỗ hổng bảo mật trong thiết kế mạng, phần mềm và phần cứng. Các cuộc tấn công này đã trở nên ít phổ biến hơn vì các cuộc tấn công DDoS có khả năng gây gián đoạn lớn hơn và tương đối dễ tạo ra với các công cụ có sẵn. Trong thực tế, hầu hết các cuộc tấn công DoS cũng có thể được chuyển thành tấn công DDoS.</p><h3 id="mot-so-cuoc-tan-cong-dos-lich-su-pho-bien-bao-gom" tabindex="-1">Một số cuộc tấn công DoS lịch sử phổ biến bao gồm: <a class="header-anchor" href="#mot-so-cuoc-tan-cong-dos-lich-su-pho-bien-bao-gom" aria-label="Permalink to &quot;Một số cuộc tấn công DoS lịch sử phổ biến bao gồm:&quot;">​</a></h3><h3 id="tan-cong-smurf" tabindex="-1">Tấn công Smurf <a class="header-anchor" href="#tan-cong-smurf" aria-label="Permalink to &quot;Tấn công Smurf&quot;">​</a></h3><p>một cuộc tấn công DoS đã từng bị khai thác trong đó một tác nhân độc hại sử dụng địa chỉ broadcast của mạng dễ bị tổn thương bằng cách gửi các gói giả mạo, dẫn đến việc tràn ngập một địa chỉ IP mục tiêu.</p><h3 id="ping-flood" tabindex="-1">Ping flood <a class="header-anchor" href="#ping-flood" aria-label="Permalink to &quot;Ping flood&quot;">​</a></h3><p>cuộc tấn công từ chối dịch vụ đơn giản này dựa trên việc tràn ngập mục tiêu bằng các gói ICMP (ping). Bằng cách tràn ngập mục tiêu với nhiều ping hơn khả năng phản hồi hiệu quả, từ chối dịch vụ có thể xảy ra. Cuộc tấn công này cũng có thể được sử dụng như một cuộc tấn công DDoS.</p><h3 id="ping-of-death" tabindex="-1">Ping of Death <a class="header-anchor" href="#ping-of-death" aria-label="Permalink to &quot;Ping of Death&quot;">​</a></h3><p>thường bị nhầm lẫn với tấn công ping flood, tấn công ping of death liên quan đến việc gửi một gói tin lỗi đến máy mục tiêu, dẫn đến hành vi bất lợi như lỗi hệ thống.</p><h2 id="ddos" tabindex="-1">DDoS <a class="header-anchor" href="#ddos" aria-label="Permalink to &quot;DDoS&quot;">​</a></h2><p>Trong <strong>cuộc tấn công từ chối dịch vụ phân tán (tấn công DDoS)</strong>, lưu lượng truy cập đến tràn ngập nạn nhân bắt nguồn từ nhiều nguồn khác nhau. Điều này khiến việc ngăn chặn cuộc tấn công đơn giản bằng cách chặn một nguồn duy nhất là gần như không thể. Một số cuộc tấn công DoS có ý nghĩa lịch sử là gì?</p><p>DoS sử dụng một kết nối duy nhất, trong khi tấn công DDoS sử dụng nhiều nguồn lưu lượng tấn công, thường ở dạng botnet. Nói chung, nhiều cuộc tấn công về cơ bản tương tự nhau và có thể được thực hiện bằng một hoặc nhiều nguồn lưu lượng độc hại.</p><p>Nguồn:</p><ul><li><a href="https://en.wikipedia.org/wiki/Denial-of-service_attack" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Denial-of-service_attack</a></li><li><a href="https://www.cloudflare.com/learning/ddos/glossary/denial-of-service/" target="_blank" rel="noreferrer">https://www.cloudflare.com/learning/ddos/glossary/denial-of-service/</a></li></ul>',20)]))}const m=c(i,[["render",o]]);export{s as __pageData,m as default};
